const input = $input.first().json;
const body = input.body || input;
const url = body.url || '';

// Fetch the page
const http = this.helpers.httpRequest.bind(this.helpers);
const resp = await http({ method: 'GET', url: url, json: false });
const html = resp || '';

// Extract title
let title = '';
const ti = html.indexOf('<title>');
if (ti >= 0) {
  const te = html.indexOf('</title>', ti);
  if (te > ti) title = html.substring(ti + 7, te).trim();
}

// Extract price
let price = 0;
const euroPos = html.indexOf('\u20AC');
if (euroPos >= 0) {
  const after = html.substring(euroPos, euroPos + 30).match(/[\d.]+/);
  if (after) price = parseInt(after[0].replace(/\./g, ''));
}

// Extract typology
const typo = html.match(/ (T\d|V\d) /);
const typology = typo ? typo[1].toUpperCase() : '';

// Extract area
const areaMatch = html.match(/(\d+)\s*m[\u00b22]/i);
const area = areaMatch ? parseInt(areaMatch[1]) : 0;

return [{ json: { titulo: title, preco: price, tipologia: typology, area: area, url_original: url } }];
